import { NextRequest, NextResponse } from 'next/server';
import nodemailer from 'nodemailer';
import { createClient, isSupabaseConfigured } from '@/lib/supabase/server';

const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_APP_PASSWORD,
  },
});

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { leadId, to, subject, body: emailBody, recordCommunication = true } = body;

    if (!to || !subject || !emailBody) {
      return NextResponse.json(
        { success: false, message: 'To, subject, and body are required' },
        { status: 400 }
      );
    }

    if (!process.env.EMAIL_USER || !process.env.EMAIL_APP_PASSWORD) {
      return NextResponse.json(
        { success: false, message: 'Email service not configured' },
        { status: 500 }
      );
    }

    await transporter.sendMail({
      from: process.env.EMAIL_USER,
      to,
      subject,
      html: emailBody.replace(/\n/g, '<br>'),
    });

    if (recordCommunication && leadId && isSupabaseConfigured()) {
      const supabase = await createClient();
      await supabase.from('communications').insert({
        lead_id: leadId,
        type: 'email',
        direction: 'outbound',
        subject,
        body: emailBody,
      });
    }

    return NextResponse.json({ success: true });
  } catch (error: unknown) {
    console.error('Error sending email:', error);
    const err = error as { code?: string; message?: string };
    let msg = 'Failed to send email';
    if (err.code === 'EAUTH') msg = 'Email authentication failed';
    return NextResponse.json({ success: false, message: msg }, { status: 500 });
  }
}
